    "category": "scene",
    "prompt": "{\"type\":\"infographic poster\",\"style\":\"cute flat vector illustration, cozy, warm, soft shading, {argument name=\\\"color palette\\\" default=\\\"pastel Morandi colors, soft pinks, purples, and warm tones\\\"}\",\"character\":\"{argument name=\\\"character description\\\" default=\\\"young woman with shoulder-length brown hair wearing a pinkish-purple shirt\\\"}\",\"layout\":{\"structure\":\"4 rows, 3 columns. Top row is a merged header. Rows 2-4 contain 9 individual panels.\",\"header\":{\"title\":\"{argument name=\\\"main title\\\" default=\\\"情绪不好了？\\\"}\",\"subtitle\":\"{argument name=\\\"subtitle\\\" default=\\\"8个让你瞬间变好的方法\\\"}\",\"sub_subtitle\":\"写给焦虑的你，快来看看\",\"visual\":\"character hugging herself, surrounded by yellow sparkles and hearts\"},\"grid_panels\":[{\"id\":1,\"title\":\"1. 深呼吸\",\"text\":\"调节神经，缓解紧张情绪。\",\"visual\":\"character with eyes closed, smiling, surrounded by clouds\"},{\"id\":2,\"title\":\"2. 去户外散步\",\"text\":\"接触自然，让心静下来。\",\"visual\":\"character walking outdoors among green trees and bushes\"},{\"id\":3,\"title\":\"3. 写情绪日记\",\"text\":\"把烦恼写下，大脑会更轻松。\",\"visual\":\"character sitting at a desk writing in a notebook with a pen, floating hearts\"},{\"id\":4,\"title\":\"4. 抱抱自己\",\"text\":\"给予自己温暖和安慰。\",\"visual\":\"character hugging herself with eyes closed, floating hearts\"},{\"id\":5,\"title\":\"5. 听听音乐\",\"text\":\"让舒缓的旋律治愈心灵。\",\"visual\":\"character wearing large white headphones, eyes closed, floating colorful music notes\"},{\"id\":6,\"title\":\"6. 找人倾诉\",\"text\":\"分享你的烦恼，让压力释放。\",\"visual\":\"character holding a smartphone, talking to another similar-looking girl, floating hearts\"},{\"id\":7,\"title\":\"7. 看看天空\",\"text\":\"感受天空的辽阔，让心情变好。\",\"visual\":\"character looking up at a blue sky with white clouds and sparkles\"},{\"id\":8,\"title\":\"8. 冥想\",\"text\":\"专注于呼吸，找回内心的宁静。\",\"visual\":\"an open notebook, a pen, and a pink flower on a desk\"},{\"id\":9,\"title\":\"none\",\"text\":\"{argument name=\\\"footer text\\\" default=\\\"转发收藏，每天都要关爱自己！\\\"}\",\"visual\":\"character sitting cross-legged in a meditation pose, eyes closed, with a glowing halo behind her head\"}]}}",
